@pytest.fixture
def real_gateway(mining_address):
    """
    Start a real PearlGateway using config.yaml settings.

    This fixture connects to a real Pearl node (configured in config.yaml)
    for end-to-end integration testing.

    Yields the PearlGateway instance.
    """
    from pearl_gateway.pearl_gateway import PearlGateway

    # Set mining address for the gateway
    os.environ["PEARLD_MINING_ADDRESS"] = mining_address

    # Create gateway with temp socket to avoid conflicts between tests
    gateway = PearlGateway(use_temp_socket=True, debug_mode=True)

    # Start gateway in background thread
    loop = asyncio.new_event_loop()
    stop_event = threading.Event()
    ready_event = threading.Event()

    def run_gateway():
        asyncio.set_event_loop(loop)

        async def start_and_run():
            await gateway.start()
            ready_event.set()
            while not stop_event.is_set():
                await asyncio.sleep(0.1)
            await gateway.stop()

        loop.run_until_complete(start_and_run())

    thread = threading.Thread(target=run_gateway, daemon=True)
    thread.start()

    # Wait for gateway to be ready
    if not ready_event.wait(timeout=30.0):
        pytest.fail("Gateway failed to start within 30 seconds")

    yield gateway

    # Cleanup
    stop_event.set()
    thread.join(timeout=10.0)
    loop.close()
